const input = $input.all();
const output = [];

for (const item of input) {
  const data = item.json;

  const records = Array.isArray(data) ? data : [data];

  for (const x of records) {
    output.push({
      json: {
        intel_id: String(x.intel_id || '').trim(),
        source: String(x.source || 'Demo CTI Feed').trim(),

        indicator_value: String(x.indicator_value || '').trim().toLowerCase(),
        indicator_type: String(x.indicator_type || '').trim().toLowerCase(),

        threat_actor: String(x.threat_actor || '').trim(),
        actor_origin: String(x.actor_origin || '').trim(),
        actor_motivation: String(x.actor_motivation || '').trim(),

        malware: String(x.malware || '').trim(),
        malware_type: String(x.malware_type || '').trim(),

        campaign: String(x.campaign || '').trim(),
        campaign_description: String(x.campaign_description || '').trim(),

        confidence: Number(x.confidence || 0),
        first_seen: String(x.first_seen || '').trim(),
        last_seen: String(x.last_seen || '').trim(),

        techniques: Array.isArray(x.techniques) ? x.techniques : []
      }
    });
  }
}

return output;

const output = [];

for (const item of $input.all()) {
  const x = item.json;

  for (const t of x.techniques || []) {
    output.push({
      json: {
        intel_id: x.intel_id,
        malware: x.malware,
        technique_id: String(t.technique_id || '').trim(),
        technique_name: String(t.name || '').trim(),
        tactic: String(t.tactic || '').trim()
      }
    });
  }
}

return output;
